import { wallLength } from '@/geometry/wallGeometry';
import InputField from './InputField';
import styles from './PropertiesPanel.module.css';

function WallProperties({ wall, dispatch, floorId }) {
  const len = wallLength(wall);

  const updateWall = (updates) => {
    dispatch({ type: 'WALL_UPDATE', floorId, wall: { id: wall.id, ...updates } });
  };

  return (
    <div>
      <div className={styles.title}>Wall</div>
      <div className={styles.subtitle}>Start Point</div>
      <InputField
        label="X" type="number" suffix="mm"
        value={Math.round(wall.start.x)}
        onChange={(v) => updateWall({ start: { ...wall.start, x: v } })}
      />
      <InputField
        label="Y" type="number" suffix="mm"
        value={Math.round(wall.start.y)}
        onChange={(v) => updateWall({ start: { ...wall.start, y: v } })}
      />
      <div className={styles.subtitle}>End Point</div>
      <InputField
        label="X" type="number" suffix="mm"
        value={Math.round(wall.end.x)}
        onChange={(v) => updateWall({ end: { ...wall.end, x: v } })}
      />
